export const BASE_URL = 'https://mate-api.herokuapp.com';

export const NEWS_TRENDING_URL = 'https://bing-news-search1.p.rapidapi.com/news/trendingtopics?safeSearch=Off&textFormat=Raw';

export const NEWS_CATEGORY_URL = 'https://bing-news-search1.p.rapidapi.com/news?textFormat=Raw&safeSearch=Off';

export const setUrlArticle = title => `https://newscatcher.p.rapidapi.com/v1/search?q=${title}&lang=en&sort_by=relevancy&search_in=title&page=1&media=True`;

export const optionsNews = {
  method: 'GET',
  headers: {
    // 'content-type': 'application/json; charset=utf-8',
    'x-bingapis-sdk': 'true',
    'x-rapidapi-key': '43f5b0b1b7msh98b68ce351846cdp1fe9bdjsn077a7897ccfa',
    'x-rapidapi-host': 'bing-news-search1.p.rapidapi.com',
  },
};

export const optionsArticles = {
  method: 'GET',
  headers: {
    'x-rapidapi-key': '43f5b0b1b7msh98b68ce351846cdp1fe9bdjsn077a7897ccfa',
    'x-rapidapi-host': 'newscatcher.p.rapidapi.com',
  },
};

export const request = (url, opti) => (
  fetch(url, option)
    .then(response => response.json())
    .then(res => res)
);

// export const getTrendingNews = async() => {
//   const result = await request(NEWS_TRENDING_URL, optionsNews);
//   return result;
// };

export const getArticlesNews = async(query) => {
  const result = await request(setUrlArticle(query), optionsNews);

  return result;
};
